var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"관리자님, 몸에 이상은 없으십니까?","JPN":"管理者様、身体に異常はありませんか？","ENG":"Administrator, are you okay?","TWN":"管理者，你的身體沒事吧？"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"너무 걱정 말게나. 처음부터 믿는 구석이 있어서 마주했던 거니까.","JPN":"心配するな。最初から大丈夫だとわかっていて対戦したんだ。","ENG":"Don't worry too much. I only confronted her because I knew I could.","TWN":"別太擔心，從一開始我就是心裡有譜才敢跟她正面對上的。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네야말로 많이 변했군. 상태는 좀 어떤가?","JPN":"君こそだいぶ変わったな。調子はどうだ？","ENG":"You’ve changed a lot. How do you feel?","TWN":"倒是你，真的變了好多。狀態如何？"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"……염려해 주신 덕분에.","JPN":"……お気遣い頂いたおかげで。","ENG":"...Good, all thanks to you.","TWN":"……托你的福。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"앞서 간 전우들을 위해, 패전을 만회할 기회를 주셔서 감사할 따름입니다.","JPN":"先に倒れた戦友たちのために、敗戦を挽回するチャンスを与えていただき感謝の限りです。","ENG":"I’m grateful for this opportunity to make up for my past defeat and for my dead comrades.","TWN":"謝謝你給我這個機會，能夠為先走一步的戰友扭轉敗仗。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"하지만 지금은, 저보단……","JPN":"でも今は、私より……","ENG":"But now is not about me, but rather...","TWN":"不過現在，更重要的是……"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하긴, 그렇지.","JPN":"ああ、そうだな。","ENG":"Yes, I suppose you are right.","TWN":"也是。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"묻고 싶은 것이 많겠군.","JPN":"聞きたいことがたくさんあるだろう。","ENG":"You must have a lot of questions.","TWN":"你應該有很多問題想問吧。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……그래. 관리자.","JPN":"……そうだ、管理者。","ENG":"...Yes, Administrator.","TWN":"……是的，管理者。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"메이즈 전대장을 저 지경으로 만든 건……. 차차 듣도록 하지.","JPN":"メイズ戦隊長をあんなふうにしたのは……いやまた今度聞くとしよう。","ENG":"About making the Maze Division Commander like that… I'll listen later.","TWN":"把梅茲戰隊長變成那樣……我還是慢慢聽你解釋吧。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"이제야 기억이 떠올랐어. 왜 네가 느닷없이 종적을 감췄는지.","JPN":"やっと思い出したんだ。お前がなぜいきなり影を潜めたのか。","ENG":"I now remember. Why you suddenly disappeared.","TWN":"我現在才想起來，你為什麼突然就消聲匿跡了。"},"stage":{"bg":"THRONE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"어째서 프로토콜을 바꾼 거지? 말해!","JPN":"なぜプロトコルを変えた？　話せ！","ENG":"Why did you change the protocol? Tell me!","TWN":"你為什麼要改變協議？快說！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"심정은 알겠지만 진정하게. 변수가 생겼어.","JPN":"気持ちはわかるが、落ち着いてくれ。想定外のことが起きたんだ。","ENG":"I understand your frustration but calm down. There was a variable.","TWN":"我理解你的心情，但是你冷靜點，發生了意外的變數。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"변수라고……?","JPN":"想定外のことだと……？","ENG":"Variable...?","TWN":"變數……？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그녀가, 탐미엘에게 상처를 입혔어.","JPN":"彼女が、タミエルに傷を付けた。","ENG":"She hurt Tammiel.","TWN":"她讓塔米爾受傷了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"……뭐?","JPN":"……何だと？","ENG":"...What did you say?","TWN":"……什麼？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"불가능해. 그런 말도 안 되는 일이 가능하다고?","JPN":"あり得ない。そんなことが可能なのか？","ENG":"That doesn't make sense. How can something like that happen?","TWN":"不可能。怎麼會發生這種不可能的事？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};